1	// Solar panels — OWNED by Dev A
2	// Placement strategy (GLB-driven, baked positions are NOT used for layout):
3	//   1. After the GLB is fully visible (glbStable), sample its XZ bbox with a
4	//      grid of vertical raycasts at panel-pitch resolution. Each successful
5	//      hit on a roof-like face (normal.y above threshold) becomes a candidate.
6	//   2. Score each candidate by tilt + flatness so the algorithm prefers the
7	//      part of the roof a real installer would target.
8	//   3. Greedy placement walks candidates from best score down, accepting one
9	//      only if (a) all four corners land on the same roof slope (no eave or
10	//      ridge overhang, no straddling two pitches), (b) it doesn't overlap a
11	//      panel already placed, (c) it isn't on a baked obstruction (chimney,
12	//      dormer, vent).
13	//   4. Stops once we hit the count requested by the k-NN sizer (design.
14	//      modulePositions.length).
15	//
16	// Reveal animation: the orchestrator ticks `placedCount` up from 0 to the
17	// total module count over a few seconds. We slice the projected positions
18	// array by that count, and each panel mesh, on mount, "drops" along its
19	// (face) normal from ~1.5 m above the final spot down onto the roof with an
20	// ease-out cubic — so panels appear to land one by one in order.
21	
22	'use client';
23	
24	import { useEffect, useMemo, useRef } from 'react';
25	import { useFrame, useThree } from '@react-three/fiber';
26	import {
27	  Box3,
28	  Group,
29	  Object3D,
30	  Quaternion,
31	  Raycaster,
32	  Vector3,
33	} from 'three';
34	import { useStore } from '@/lib/store';
35	import { useHouseGeometry } from './HouseGeometry';
36	
37	// Real-world panel SKU catalogue. Each variant is a market-available form
38	// factor; the placement algorithm tries the full-size variant first and
39	// falls back to compact / mini if the roof can't fit the target count.
40	//   • AIKO Comet / Trina Vertex S+ — full residential 470-475 W.
41	//   • Half-cell 220 W — compact module for tight roof zones.
42	//   • Mini 120 W — fills the leftover slivers between dormers / chimneys.
43	// Wattage is what's used to convert the kWp target into a panel count,
44	// so smaller panels naturally produce a denser layout.
45	interface PanelVariant {
46	  name: string;
47	  size: [number, number, number];
48	  wattPeak: number;
49	}
50	const PANEL_VARIANT_FULL_AIKO: PanelVariant = {
51	  name: 'AIKO 475 W',
52	  size: [1.722, 0.03, 1.134],
53	  wattPeak: 475,
54	};
55	const PANEL_VARIANT_FULL_TRINA: PanelVariant = {
56	  name: 'Trina 475 W',
57	  size: [1.762, 0.03, 1.134],
58	  wattPeak: 475,
59	};
60	const PANEL_VARIANT_COMPACT: PanelVariant = {
61	  name: 'Half-cell 220 W',
62	  size: [1.10, 0.03, 0.70],
63	  wattPeak: 220,
64	};
65	const PANEL_VARIANT_MINI: PanelVariant = {
66	  name: 'Mini 120 W',
67	  size: [0.78, 0.03, 0.55],
68	  wattPeak: 120,
69	};
70	// Distance from the raycast hit point (roof surface) to the panel mesh
71	// CENTRE along the surface normal. Real photovoltaic panels sit on rail
72	// systems that lift them 10-15 cm above the tile. Half-thickness of the
73	// AIKO datasheet (30 mm) is 15 mm, so with LIFT = 0.13 m the panel BASE
74	// floats ~11.5 cm above the roof — visibly mounted, not embedded.
75	const PANEL_LIFT_M = 0.13;
76	const PANEL_COLOR = '#1a3a6e';
77	const DROP_HEIGHT_M = 1.5;
78	const DROP_DURATION_MS = 550;
79	/** Above-roof origin for downward raycasts (must comfortably exceed any
80	 *  recentred GLB height). */
81	const RAY_ORIGIN_Y = 60;
82	/** Reject hits whose normal Y is below this threshold (= not roof-like:
83	 *  walls, ground plane, vertical surfaces). Kept moderate (0.3) so shallow
84	 *  Hunyuan slopes register as roof but vertical faces don't. */
85	const ROOF_NORMAL_Y_MIN = 0.3;
86	/** Two probe hits are considered to be on the same pitch if their normals
87	 *  agree by at least this dot product. Below ~0.85 means the angle between
88	 *  them exceeds ~30° — almost certainly different surfaces (dormer side,
89	 *  chimney face, window frame). */
90	const SAME_PITCH_DOT = 0.85;
91	/** A probe is considered an OBSTACLE relative to the candidate centre if
92	 *  the GLB surface at that probe is more than this much higher (along the
93	 *  panel normal) — picks up chimneys, dormer cubes, antennas, skylight
94	 *  frames protruding above the roof tiles. */
95	const OBSTACLE_Y_DELTA_M = 0.25;
96	/** Extra margin around the panel footprint when probing for obstacles —
97	 *  guarantees adjacent obstacles still flag the panel even if the corner
98	 *  itself was clean. */
99	const OBSTACLE_PROBE_MARGIN_M = 0.18;
100	/** Extra margin around analysis.json obstructions (chimneys, dormers, vents). */
101	const OBSTRUCTION_MARGIN_M = 0.45;
102	/** Overlap factor — panels can be ALMOST flush (12 % gap of the short
103	 *  side) but never sit on top of each other. */
104	const PANEL_OVERLAP_FACTOR = 0.88;
105	/** Sampling grid step as a fraction of panel size. Smaller = denser grid =
106	 *  more candidates but slower (each cell = one raycast). 0.55 packs ~2
107	 *  samples per panel footprint, enough to find every viable position. */
108	const GRID_STEP_RATIO = 0.55;
109	const UP = new Vector3(0, 1, 0);
110	
111	interface ProjectedPanel {
112	  faceId: number;
113	  x: number;
114	  y: number;
115	  z: number;
116	  normal: [number, number, number];
117	  quaternion: Quaternion;
118	}
119	
120	interface PanelLayout {
121	  panels: ProjectedPanel[];
122	  variant: PanelVariant;
123	}
124	
125	export function Panels() {
126	  const design = useStore((s) => s.design);
127	  const placedCount = useStore((s) => s.placedCount);
128	  // Wait for `glbStable` (post-morph) — not just `glbLoaded` (mounted) —
129	  // before doing any raycast-based projection. This guarantees the GLB is
130	  // at full opacity AND its world matrix has settled (the morph animates
131	  // the parent group's scale 0.6 → 1.0).
132	  const glbStable = useStore((s) => s.glbStable);
133	  const glbHeight = useStore((s) => s.glbHeight);
134	  const { modulePositions: recenteredPositions, obstructions } =
135	    useHouseGeometry();
136	  const sceneRoot = useThree((s) => s.scene);
137	
138	  const glbRoofAreaM2 = useStore((s) => s.glbRoofAreaM2);
139	
140	  // Variant cascade: try the brand-recommended full-size first, then fall
141	  // back to smaller form factors for tighter roofs. The algorithm uses the
142	  // first variant that hits ≥ the target kWp.
143	  const variants: PanelVariant[] = useMemo(() => {
144	    const full =
145	      design?.moduleBrand === 'Trina'
146	        ? PANEL_VARIANT_FULL_TRINA
147	        : PANEL_VARIANT_FULL_AIKO;
148	    return [full, PANEL_VARIANT_COMPACT, PANEL_VARIANT_MINI];
149	  }, [design?.moduleBrand]);
150	
151	  // Pre-pick the most appropriate variant given the actual roof area on the
152	  // GLB. We compute, for each variant, the m² of roof needed to cover the
153	  // k-NN target kWp; the first variant whose footprint fits within the
154	  // packing-efficiency-adjusted roof area is the one we'll start with.
155	  // Falls through to the smallest if none fit (rare on real homes).
156	  // Packing efficiency 0.45 accounts for: only ~50% of the roof is south-
157	  // facing, then 80-90% of THAT is reachable after edges & obstacles.
158	  const PACKING_EFFICIENCY = 0.45;
159	  const preferredVariant = useMemo<PanelVariant>(() => {
160	    if (!design || !glbRoofAreaM2) return variants[0];
161	    const targetKwp = design.totalKwp || 0;
162	    const usableM2 = glbRoofAreaM2 * PACKING_EFFICIENCY;
163	    for (const v of variants) {
164	      const targetPanels = Math.max(1, Math.ceil((targetKwp * 1000) / v.wattPeak));
165	      const areaNeeded = targetPanels * v.size[0] * v.size[2];
166	      if (areaNeeded <= usableM2) return v;
167	    }
168	    return variants[variants.length - 1];
169	  }, [design, glbRoofAreaM2, variants]);
170	
171	  // Recompute projected positions whenever the GLB is (re)loaded or its
172	  // measured height changes. We re-find the GLB root each time because the
173	  // R3F scene tree mutates around the morph animation.
174	  const layout = useMemo<PanelLayout | null>(() => {
175	    if (!glbStable) return null;
176	    if (!design) return null;
177	
178	    // Locate the GLB root in the R3F scene. Flagged with userData.isGlbRoof
179	    // by <LoadedGlb/>. Forces world matrix update so raycasts use the post-
180	    // morph (scale 1.0) transform.
181	    let glbRoot: Object3D | null = null;
182	    sceneRoot.traverse((o) => {
183	      if (!glbRoot && o.userData?.isGlbRoof) glbRoot = o;
184	    });
185	    if (!glbRoot) return null;
186	    const glb = glbRoot as Object3D;
187	    glb.updateMatrixWorld(true);
188	
189	    const raycaster = new Raycaster();
190	    const downRay = new Vector3(0, -1, 0);
191	
192	    // Cast a single downward ray onto the GLB. Returns null on miss or on
193	    // non-roof hit (vertical wall, ground plane).
194	    const projectPoint = (x: number, z: number) => {
195	      raycaster.set(new Vector3(x, RAY_ORIGIN_Y, z), downRay);
196	      const hits = raycaster.intersectObject(glb, true);
197	      if (hits.length === 0) return null;
198	      const hit = hits[0];
199	      if (!hit.face) return null;
200	      const worldNormal = hit.face.normal
201	        .clone()
202	        .transformDirection(hit.object.matrixWorld)
203	        .normalize();
204	      if (worldNormal.y < ROOF_NORMAL_Y_MIN) return null;
205	      return { point: hit.point.clone(), normal: worldNormal };
206	    };
207	
208	    const glbBox = new Box3().setFromObject(glb);
209	    const targetKwp = design.totalKwp || 0;
210	    const obstructionRadii = obstructions.map((ob) => ({
211	      x: ob.position[0],
212	      z: ob.position[2],
213	      r: ob.radius + OBSTRUCTION_MARGIN_M,
214	    }));
215	
216	    // Greedy packer for ONE variant. Returns the panels it could fit.
217	    const packForVariant = (variant: PanelVariant): ProjectedPanel[] => {
218	      const stepX = variant.size[0] * GRID_STEP_RATIO;
219	      const stepZ = variant.size[2] * GRID_STEP_RATIO;
220	      const halfW = variant.size[0] / 2;
221	      const halfH = variant.size[2] / 2;
222	      const xStart = glbBox.min.x + halfW + 0.05;
223	      const xEnd = glbBox.max.x - halfW - 0.05;
224	      const zStart = glbBox.min.z + halfH + 0.05;
225	      const zEnd = glbBox.max.z - halfH - 0.05;
226	
227	      // Sample the GLB roof at panel-pitch resolution.
228	      interface Candidate {
229	        point: Vector3;
230	        normal: Vector3;
231	        score: number;
232	      }
233	      const candidates: Candidate[] = [];
234	      for (let x = xStart; x <= xEnd + 1e-6; x += stepX) {
235	        for (let z = zStart; z <= zEnd + 1e-6; z += stepZ) {
236	          const hit = projectPoint(x, z);
237	          if (!hit) continue;
238	          const tiltDeg =
239	            (Math.acos(Math.max(0, Math.min(1, hit.normal.y))) * 180) / Math.PI;
240	          const tiltScore = Math.max(0, 1 - Math.abs(tiltDeg - 32) / 50);
241	          candidates.push({
242	            point: hit.point,
243	            normal: hit.normal,
244	            score: hit.normal.y * (0.5 + 0.5 * tiltScore),
245	          });
246	        }
247	      }
248	      candidates.sort((a, b) => b.score - a.score);
249	
250	      const minDist =
251	        Math.min(variant.size[0], variant.size[2]) * PANEL_OVERLAP_FACTOR;
252	      const minDistSq = minDist * minDist;
253	      const targetCount = Math.max(
254	        1,
255	        Math.round((targetKwp * 1000) / variant.wattPeak),
256	      );
257	
258	      const placed: ProjectedPanel[] = [];
259	      for (const cand of candidates) {
260	        if (placed.length >= targetCount) break;
261	
262	        // (a) overlap with previously placed panels
263	        let overlaps = false;
264	        for (const p of placed) {
265	          const dx = cand.point.x - p.x;
266	          const dz = cand.point.z - p.z;
267	          if (dx * dx + dz * dz < minDistSq) {
268	            overlaps = true;
269	            break;
270	          }
271	        }
272	        if (overlaps) continue;
273	
274	        // (b) on a baked obstruction (chimney / dormer / vent)
275	        let onObstruction = false;
276	        for (const ob of obstructionRadii) {
277	          const dx = cand.point.x - ob.x;
278	          const dz = cand.point.z - ob.z;
279	          if (dx * dx + dz * dz < ob.r * ob.r) {
280	            onObstruction = true;
281	            break;
282	          }
283	        }
284	        if (onObstruction) continue;
285	
286	        // (c) 8-PROBE validation: corners + edge midpoints + slightly-outside
287	        // probes. Every probe must (1) hit the GLB, (2) match the centre's
288	        // pitch (no overhang, no straddling), and (3) NOT be significantly
289	        // higher than the centre (= adjacent chimney / dormer / skylight
290	        // frame). If any probe fails, we skip the candidate AND apply a
291	        // safety margin around obstacles by virtue of OBSTACLE_PROBE_MARGIN.
292	        const n = cand.normal;
293	        let uAxis = new Vector3(1, 0, 0).sub(n.clone().multiplyScalar(n.x));
294	        if (uAxis.lengthSq() < 1e-6) uAxis = new Vector3(0, 0, 1);
295	        uAxis.normalize();
296	        const vAxis = new Vector3().crossVectors(n, uAxis).normalize();
297	
298	        const u = halfW + OBSTACLE_PROBE_MARGIN_M;
299	        const v = halfH + OBSTACLE_PROBE_MARGIN_M;
300	        // 4 corners (with margin) + 4 edge midpoints (with margin).
301	        const probes = [
302	          [u, v],
303	          [u, -v],
304	          [-u, v],
305	          [-u, -v],
306	          [u, 0],
307	          [-u, 0],
308	          [0, v],
309	          [0, -v],
310	        ];
311	
312	        let valid = true;
313	        for (const [pu, pv] of probes) {
314	          const pw = new Vector3()
315	            .copy(cand.point)
316	            .addScaledVector(uAxis, pu)
317	            .addScaledVector(vAxis, pv);
318	          const cp = projectPoint(pw.x, pw.z);
319	          if (!cp) {
320	            // Probe missed → panel overhangs the eave / ridge.
321	            valid = false;
322	            break;
323	          }
324	          if (cp.normal.dot(n) < SAME_PITCH_DOT) {
325	            // Probe on a different pitch → adjacent dormer face / wall.
326	            valid = false;
327	            break;
328	          }
329	          // Project the height delta along the centre's normal — protrusion
330	          // of an obstacle is measured ALONG the panel's slope, not world Y.
331	          const delta = cp.point.clone().sub(cand.point).dot(n);
332	          if (delta > OBSTACLE_Y_DELTA_M) {
333	            // Probe is markedly higher than the centre → chimney / dormer
334	            // body / skylight frame sticking up adjacent to the panel.
335	            valid = false;
336	            break;
337	          }
338	        }
339	        if (!valid) continue;
340	
341	        placed.push({
342	          faceId: 0,
343	          x: cand.point.x,
344	          y: cand.point.y,
345	          z: cand.point.z,
346	          normal: [n.x, n.y, n.z],
347	          quaternion: new Quaternion().setFromUnitVectors(UP, n),
348	        });
349	      }
350	      return placed;
351	    };
352	
353	    // Try preferredVariant first (chosen above based on roof area), then
354	    // fall back to the rest of the cascade if it under-delivers.
355	    const orderedVariants = [
356	      preferredVariant,
357	      ...variants.filter((v) => v !== preferredVariant),
358	    ];
359	    let bestLayout: PanelLayout | null = null;
360	    let bestKwpDelivered = -1;
361	    for (const variant of orderedVariants) {
362	      const panels = packForVariant(variant);
363	      const deliveredKwp = (panels.length * variant.wattPeak) / 1000;
364	      if (deliveredKwp > bestKwpDelivered) {
365	        bestKwpDelivered = deliveredKwp;
366	        bestLayout = { panels, variant };
367	      }
368	      // Acceptable: this variant covers ≥ 90 % of target — stop cascading.
369	      if (deliveredKwp >= targetKwp * 0.9 || deliveredKwp >= targetKwp) {
370	        bestLayout = { panels, variant };
371	        bestKwpDelivered = deliveredKwp;
372	        break;
373	      }
374	    }
375	
376	    return bestLayout;
377	  }, [
378	    glbStable,
379	    glbHeight,
380	    design,
381	    recenteredPositions,
382	    obstructions,
383	    sceneRoot,
384	    variants,
385	    preferredVariant,
386	  ]);
387	
388	  const projectedPositions = layout?.panels ?? null;
389	  const panelSize = layout?.variant.size ?? PANEL_VARIANT_FULL_AIKO.size;
390	
391	  // Publish the actual placement count so the orchestrator's drop-animation
392	  // loop can size itself correctly (the variant cascade may pick compact
393	  // panels and produce more than design.modulePositions.length).
394	  const setPanelTargetCount = useStore((s) => s.setPanelTargetCount);
395	  useEffect(() => {
396	    setPanelTargetCount(projectedPositions?.length ?? 0);
397	  }, [projectedPositions, setPanelTargetCount]);
398	
399	  if (!projectedPositions || projectedPositions.length === 0) return null;
400	
401	  // The variant cascade already trimmed to the right count (target kWp /
402	  // variant.wattPeak). Just slice by the animation cadence.
403	  const visible = projectedPositions.slice(
404	    0,
405	    Math.min(placedCount, projectedPositions.length),
406	  );
407	
408	  return (
409	    <group>
410	      {visible.map((p, i) => {
411	        const lx = p.x + p.normal[0] * PANEL_LIFT_M;
412	        const ly = p.y + p.normal[1] * PANEL_LIFT_M;
413	        const lz = p.z + p.normal[2] * PANEL_LIFT_M;
414	        return (
415	          <DroppingPanel
416	            key={`${p.faceId}_${p.x.toFixed(3)}_${p.z.toFixed(3)}_${i}`}
417	            finalPos={[lx, ly, lz]}
418	            normal={p.normal}
419	            quaternion={p.quaternion}
420	            size={panelSize}
421	          />
422	        );
423	      })}
424	    </group>
425	  );
426	}
427	
428	interface DroppingPanelProps {
429	  finalPos: [number, number, number];
430	  normal: [number, number, number];
431	  quaternion: Quaternion;
432	  size: [number, number, number];
433	}
434	
435	// Animates from `finalPos + normal * DROP_HEIGHT_M` down to `finalPos` with
436	// an ease-out cubic over DROP_DURATION_MS. Once settled, useFrame becomes a
437	// noop early-return.
438	function DroppingPanel({ finalPos, normal, quaternion, size }: DroppingPanelProps) {
439	  const groupRef = useRef<Group>(null);
440	  const mountedAtRef = useRef<number>(performance.now());
441	  const settledRef = useRef(false);
442	
443	  useFrame(() => {
444	    if (settledRef.current || !groupRef.current) return;
445	    const elapsed = performance.now() - mountedAtRef.current;
446	    const t = Math.min(1, elapsed / DROP_DURATION_MS);
447	    const eased = 1 - Math.pow(1 - t, 3);
448	    const offset = (1 - eased) * DROP_HEIGHT_M;
449	    groupRef.current.position.set(
450	      finalPos[0] + normal[0] * offset,
451	      finalPos[1] + normal[1] * offset,
452	      finalPos[2] + normal[2] * offset,
453	    );
454	    if (t >= 1) {
455	      settledRef.current = true;
456	      groupRef.current.position.set(finalPos[0], finalPos[1], finalPos[2]);
457	    }
458	  });
459	
460	  return (
461	    <group
462	      ref={groupRef}
463	      position={[
464	        finalPos[0] + normal[0] * DROP_HEIGHT_M,
465	        finalPos[1] + normal[1] * DROP_HEIGHT_M,
466	        finalPos[2] + normal[2] * DROP_HEIGHT_M,
467	      ]}
468	      quaternion={quaternion}
469	    >
470	      <mesh castShadow>
471	        <boxGeometry args={size} />
472	        <meshToonMaterial color={PANEL_COLOR} />
473	      </mesh>
474	    </group>
475	  );
476	}
