  agentSteps: [],
  setAgentSteps: (agentSteps) => set({ agentSteps }),
  updateStepStatus: (id, status) =>
    set((s) => ({
      agentSteps: s.agentSteps.map((step) =>
        step.id === id ? { ...step, status } : step,
      ),
    })),
  updateStepFields: (id, fields) =>
    set((s) => ({
      agentSteps: s.agentSteps.map((step) =>
        step.id === id ? { ...step, ...fields } : step,
      ),
    })),

  reset: () =>
    set({
      phase: 'idle',
      trellisStatus: 'idle',
      glbUrl: null,
      selectedHouse: null,
      customAddress: null,
      manualInputs: defaultManualInputs,
      profile: null,
      refinements: defaultRefinements,
      design: null,
      customRoofGeometry: null,
      agentSteps: [],
      placedCount: 0,
      glbLoaded: false,
      glbStable: false,
      glbHeight: null,
      panelTargetCount: 0,
      glbRoofAreaM2: null,
      glbBboxXZ: null,
    }),
}));

