3	import { motion, useSpring, useTransform } from 'framer-motion';
4	import { useEffect } from 'react';
5	import { useStore } from '@/lib/store';
6	
7	// Real-world panel surface area, used to translate the placed panel count
8	// into m² of roof covered. Defaults to AIKO 475 W (~1.95 m²) — the cascade
9	// in <Panels/> picks compact / mini for tight roofs but the area tends to
10	// land in the same ballpark since smaller panels need higher counts.
11	const PANEL_AREA_M2 = 1.722 * 1.134;
12	
13	export function KPISidebar() {
14	  const design = useStore((s) => s.design);
15	  const profile = useStore((s) => s.profile);
16	  const panelTargetCount = useStore((s) => s.panelTargetCount);
17	  const glbRoofAreaM2 = useStore((s) => s.glbRoofAreaM2);
18	
19	  const totalKwp = design?.totalKwp ?? 0;
20	  const battery = design?.batteryCapacityKwh ?? 0;
21	  const price = design?.totalPriceEur ?? 0;
22	  const payback = design?.paybackYears ?? 0;
23	  const co2 = design?.co2SavedTonsPer25y ?? 0;
24	  const consumption = profile?.annualConsumptionKwh ?? 0;
25	  const evKm = profile?.hasEv ? profile.evAnnualKm ?? 0 : 0;
26	  const evKwh = Math.round(evKm * 0.18);
27	  const residentialKwh = Math.max(0, consumption - evKwh);
28	
