584	      const hit = hits[0];
585	      if (!hit.face) return null;
586	      const worldNormal = hit.face.normal
587	        .clone()
588	        .transformDirection(hit.object.matrixWorld)
589	        .normalize();
590	      if (worldNormal.y < ROOF_NORMAL_Y_MIN) return null;
591	      return { point: hit.point.clone(), normal: worldNormal };
592	    },
