607	        const dz = point.z - p.z;
608	        if (dx * dx + dz * dz < minDistSq) return false;
609	      }
610	      // (b) baked obstruction (chimney / dormer / vent).
611	      for (const ob of obstructionRadii) {
612	        const dx = point.x - ob.x;
613	        const dz = point.z - ob.z;
614	        if (dx * dx + dz * dz < ob.r * ob.r) return false;
